package main

import (
	"context"
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context. It sandbox the script to prevent security issues.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Load only safe standard libraries (exclude os, io, debug which are dangerous)
	lua.OpenBase(L)    // Basic functions (print, type, etc.)
	lua.OpenMath(L)    // Math functions (sin, cos, etc.)
	lua.OpenString(L)  // String functions (sub, find, etc.)
	lua.OpenTable(L)   // Table functions (insert, remove, etc.)

	// Set up context with timeout to prevent infinite loops or long-running scripts
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 1*time.Second)
	defer cancel()

	// Channel to communicate results and errors between goroutines
	resChan := make(chan float64, 1)
	errChan := make(chan error, 1)

	// Run the script in a separate goroutine to handle timeout
	go func() {
		// Load and execute the script
		if err := L.DoString(script); err != nil {
			errChan <- fmt.Errorf("failed to execute Lua script: %w", err)
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			errChan <- fmt.Errorf("calculate_final_price is not a function or not defined")
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			errChan <- fmt.Errorf("failed to call calculate_final_price: %w", err)
			return
		}

		// Get the result from the Lua stack
		result := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if result.Type() != lua.LTNumber {
			errChan <- fmt.Errorf("calculate_final_price did not return a number")
			return
		}

		resChan <- float64(result.(lua.LNumber))
	}()

	// Wait for result or timeout
	select {
	case <-ctxTimeout.Done():
		return 0, fmt.Errorf("script execution timed out: %w", ctxTimeout.Err())
	case err := <-errChan:
		return 0, err
	case res := <-resChan:
		return res, nil
	}
}

func main() {
	// Example usage
	script := `
function calculate_final_price(ctx)
    -- Apply 10% discount for VIP users (tier 2)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`
	ctx := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}

	result, err := ExecutePricingScript(script, ctx)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}
	fmt.Printf("Final Price: $%.2f\n", result) // Should print 90.00
}

