			ch <- result{0, fmt.Errorf("failed to call calculate_final_price: %w", err)}
			return
		}

		// Get the result from the Lua stack
		resultVal := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if resultVal.Type() != lua.LTNumber {
			ch <- result{0, fmt.Errorf("calculate_final_price did not return a number")}
			return
		}

		ch <- result{float64(resultVal.(lua.LNumber)), nil}
	}()

	// Enforce a reasonable timeout (e.g., 1 second) to prevent infinite loops
	select {
