package main

import (
	"errors"
	"fmt"
	"github.com/yuin/gopher-lua"
)

func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	L := lua.NewState()
	defer L.Close()

	// Save initial stack level to ensure script doesn't affect subsequent stack operations
	initialStack := L.GetTop()

	// Create context table for Lua
	ctxTable := L.NewTable()
	for key, value := range ctx {
		ctxTable.RawSetString(key, lua.LNumber(value))
	}

	// Execute the user-provided Lua script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
	}

	// Pop any values pushed to the stack by L.DoString to restore initial stack state
	if L.GetTop() > initialStack {
		L.Pop(L.GetTop() - initialStack)
	}

	// Retrieve the calculate_final_price function from global scope
	L.GetGlobal("calculate_final_price")
	if L.Get(-1).Type() != lua.LTFunction {
		L.Pop(1)
		return 0, errors.New("calculate_final_price not defined or not a function")
	}

	// Push context table as argument to the function
	L.Push(ctxTable)

	// Call the calculate_final_price function
	if err := L.PCall(1, 1, nil); err != nil {
		// Pop error value from stack
		L.Pop(1)
		return 0, fmt.Errorf("function call failed: %w", err)
	}

	// Validate and extract the number result
	if result, ok := L.Get(-1).(lua.LNumber); ok {
		L.Pop(1)
		return float64(result), nil
	}
	L.Pop(1)

	return 0, errors.New("function returned non-number result")
}

func main() {
	// Example Lua script from the requirements
	script := `
function calculate_final_price(ctx)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`

	// Test cases
	ctxVIP := map[string]float64{"base_price": 100.0, "user_tier": 2}
	vipPrice, err := ExecutePricingScript(script, ctxVIP)
	if err != nil {
		fmt.Printf("VIP Price Calculation Error: %v\n", err)
	} else {
		fmt.Printf("VIP Price: %.2f\n", vipPrice) // Should output 90.00
	}

	ctxRegular := map[string]float64{"base_price": 100.0, "user_tier": 1}
